import { useEffect, useState } from "react";
import axios from "axios";

export default function LiveTextPage() {
  const [live, setLive] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchLive = async () => {
      try {
        // 서버에 요청
        const res = await axios.get(`http://localhost:5001/api/relay`, {
          params: {
            le_id: 1,
            sr_id: 0,
            g_id: "20250918WOOB0",
            inning: 1,
            order: "DESC",
          },
        });

        setLive(res.data);
      } catch (err) {
        console.error(err);
      } finally {
        setLoading(false);
      }
    };

    fetchLive();
  }, []);

  if (loading) return <p className="text-center p-4">불러오는 중...</p>;
  if (!live) return <p className="text-center p-4">데이터가 없습니다.</p>;
  console.log(live);

  return (
    <div className="max-w-2xl mx-auto p-4">
      <h1 className="text-xl font-bold mb-4">KBO 문자중계</h1>
      <div className="border rounded-lg p-4 bg-white shadow">
        <h2 className="text-lg font-semibold">
          {live.BAT_ORDER_NO}번 타자 {live.BAT_P_NM}
        </h2>
        <ul className="mt-3 space-y-2">
          {live.listData.map((play, idx) => (
            <li
              key={idx}
              className={`p-2 border-b last:border-none text-sm ${
                play.TEXTSTYLE_SC === "13" ? "text-red-600 font-bold" : ""
              }`}
            >
              {play.LIVETEXT_IF}
            </li>
          ))}
        </ul>
      </div>
    </div>
  );
}
